use consultation;

-- suppression avec réinitialisation de la valeur de l'auto-incrément
truncate annonce;


insert into annonce (nom, description, date, url, affiche)
values ('La Domartoise',
        '<p>9H TRAIL 21KM&nbsp;</p>\n<p>9H30 TRAIL 12KM</p>\n<p>9H35 RANDONNEE 7KM500</p>\n<p>COURSE ENFANTS 1000M ET 500M</p>\n<p>INSCRIPTIONS SUR COURSE 80 (KLIKEGO)</p>',
        '2026-08-30', 'https://jackynoirat.wixsite.com/sportnaturedomartois', 'domart.jpg'),
       ('Mémorial Bruno Willecoq',
        '<p>L&rsquo;&eacute;preuve des 5 Km est ouverte &agrave; tout athl&egrave;te homme ou femme, licenci&eacute; FFA ou non licenci&eacute;, de la cat&eacute;gorie minimes (ann&eacute;e de Naissance 2011-2012) aux cat&eacute;gories master.</p>\r\n<p>Les 5 Km du M&eacute;morial Bruno Willecoq ont le&nbsp;<strong>label Bronze&nbsp;FFA</strong>, et sont qualificatif pour le championnat de France du 5 Km.</p>\r\n<p>L&rsquo;&eacute;preuve des 10 Km est ouverte &agrave; tout athl&egrave;te homme ou femme, licenci&eacute; FFA ou non licenci&eacute;, de la cat&eacute;gorie cadet (ann&eacute;e de Naissance 2008-2009) aux cat&eacute;gories master.</p>\r\n<p>Les 10 Km du M&eacute;morial Bruno Willecoq ont le&nbsp;<strong>label Or&nbsp;FFA</strong>, et sont qualificatif pour le championnat de France de 10 Km.&nbsp;</p>\r\n<p>Les 10 km du M&eacute;morial Bruno Willecoq sont inscrits au Ranking World Athletics dans le calendrier 2026</p>',
        '2026-06-07', 'https://www.facebook.com/MemorialBrunoWillecoqAbbeville/', 'abbeville.jpg'),
       ('Édition estivale des 4 saisons d\'Amiens-métropole',
        '<p><strong><em>Horaires et distances des courses (&agrave; confirmer)</em></strong></p>\n<p><strong>09h15</strong>&nbsp;5 Km d&eacute;couverte &Eacute;preuve ouverte &agrave; partir de la cat&eacute;gorie Minimes, coureurs licenci&eacute;s ou non licenci&eacute;s.</p>\n<p><strong>10h00</strong> 10 Km des as Coureurs en moins de 45 minutes. Tous les temps (m&ecirc;me sup&eacute;rieurs &agrave; 45\'00) sont pris en compte. &Eacute;preuve ouverte &agrave; partir de la cat&eacute;gorie Cadets, coureurs licenci&eacute;s ou non licenci&eacute;s.</p>\n<p><strong>11h00</strong>&nbsp;10 Km des joggers &Eacute;preuve ouverte &agrave; partir de la cat&eacute;gorie Cadets, coureurs licenci&eacute;s ou non licenci&eacute;s. Joggers du dimanche, d&eacute;butants ou confirm&eacute;s en&nbsp;45 minutes et plus</p>\n<p><strong><em>Les 3 courses de 5 et 10 km sont inscrites au challenge d&eacute;partemental de la Somme.</em></strong></p>\n<p><strong><em>&nbsp; &nbsp; &nbsp; &nbsp; <span style=\"color: #e03e2d;\">&nbsp;Pas de l</span></em></strong><span style=\"color: #e03e2d;\"><strong>abel sur cette &eacute;dition</strong></span></p>\n<p><strong><em>Inscriptions aux courses</em></strong></p>\n<p>L\'inscription vous donne la possibilit&eacute; de participer &agrave; l\'ensemble des courses propos&eacute;es &nbsp;(5 Km, 10 Km populaire et 10 Km des as)</p>\n<p>Elle s\'effectue&nbsp;<strong>en ligne</strong>&nbsp;&agrave; partir de la plateforme d\'inscription en ligne de klikego. Le lien permettant de vous inscrire sera affich&eacute; sur notre site et sur le site de Courses 80 d&egrave;s que les inscriptions seront ouvertes.</p>\n<p>Toutes les informations de tarifs, dates limites d\'inscription, etc... figurent sur le plateforme d\'inscriptions ou&nbsp; sur notre site.</p>\n<p><strong>Important : Aucune inscription sur place et aucune inscription apr&egrave;s la cl&ocirc;ture des inscriptions en ligne</strong></p>\n<p>Toutes les &eacute;preuves courues se font avec le m&ecirc;me dossard et la m&ecirc;me puce de chronom&eacute;trie coll&eacute;e au dossard.</p>\n<p><strong><em>Tarifs</em></strong></p>\n<p><strong>10&nbsp;euros</strong>&nbsp;(frais d\'inscription compris)&nbsp;pour tous les coureurs sauf si vous &ecirc;tre licenci&eacute; FFA.&nbsp;</p>\n<p><strong>8&nbsp;euros</strong>&nbsp;(frais d\'inscription compris)&nbsp;pour les licenci&eacute;s FFA</p>\n<p><strong>gratuit</strong>&nbsp;si vous &ecirc;tes licenci&eacute; &agrave; l\'Amicale du Val de Somme</p>\n<p><strong>3,8 euros&nbsp;</strong>(frais d\'inscription compris) pour les minimes, uniquement autoris&eacute;s &agrave; courir le 5km</p>\n<p>L\'achat du Pack 4 &eacute;ditions + 4 m&eacute;dailles est encore possible.</p>\n<p>&nbsp;</p>',
        '2026-07-05', 'https://www.valdesomme.fr/', 'logo4saisons.jpg'),
       ('Trail des poères',
        '<p class=\"mb-0\">Le trail des Po&egrave;res sur le territoire du Val de Somme &agrave; la limite du Santerre.</p>\n<p class=\"mb-0\"><strong>3 &eacute;preuves au programme :</strong></p>\n<ul>\n<li><strong>Trail de 17 km&nbsp;</strong>avec un d&eacute;nivel&eacute; de ...... avec classement au scratch. Podium aux 3 premiers,&egrave;res.&nbsp;Ouvert &agrave; tous &agrave; partir de la cat&eacute;gorie juniors.&nbsp;Tarif : 14&euro; + frais de gestion de la plateforme.&nbsp; D&eacute;part &agrave; 10H00.</li>\n<li><strong>Trail de 8 km</strong>&nbsp;avec un d&eacute;nivel&eacute; de ....&nbsp;avec classement au scratch. Podium aux 3 premiers,&egrave;res.&nbsp;Ouvert &agrave; tous &agrave; partir de la cat&eacute;gorie cadets.&nbsp;Tarif : 8&euro; + frais de gestion de la plateforme. D&eacute;part &agrave; 10H05</li>\n<li><strong>Marche des po&egrave;res&nbsp;</strong>: marche avec ou sans b&acirc;tons sur le parcours du trail du 8km, sans chronom&eacute;trage, ni classement.&nbsp;Tarif : 8&euro; + frais de gestion de la plateforme. D&eacute;part &agrave; 10H05</li>\n</ul>\n<p class=\"mb-0\"><em><strong>Retrait des dossards</strong></em><br>le dimanche matin, rue du 8 mai (&agrave; c&ocirc;t&eacute; de la mairie) &agrave; partir de 8H30<br><br>Venez nombreux d&eacute;couvrir des parcours surprenants sur le territoire de Marcelcave.</p>',
        '2026-04-26', 'https://www.facebook.com/traildespoeres?locale=fr_FR', 'trailmarcelcave.jpg'),
       ('Trail des Muches',
        '<p class=\"mb-0\">Venez d&eacute;couvrir et courir sur des parcours que nous avons voulus&nbsp;<strong>vari&eacute;s, techniques et surprenants</strong>&nbsp;</p>\n<p class=\"mb-0\">Profitez &eacute;galement de&nbsp;<strong>belles &eacute;preuves enfants</strong>, afin de promouvoir l&rsquo;activit&eacute; physique chez les plus jeunes&nbsp;</p>\n<p class=\"mb-0\">Sans oublier le&nbsp;<strong>v&eacute;ritable esprit Trail</strong>&nbsp;: convivialit&eacute;, partage et une&nbsp;<strong>3ᵉ mi-temps de qualit&eacute;</strong>&nbsp;</p>\n<p class=\"mb-0\"><strong>Nos courses :</strong></p>\n<ul>\n<li>\n<p class=\"mb-0\"><strong>Trail \"Les Muches\"</strong>&nbsp;: 18 km &ndash; env. 250 m D+ &ndash; 85 % en chemins dont la moiti&eacute; en sous-bois &ndash; n&eacute;s en 2008 ou avant</p>\n</li>\n<li>\n<p class=\"mb-0\"><strong>Trail \"La Carri&egrave;re\"</strong>&nbsp;: 6 km &ndash; env. 40 m D+ &ndash; 75 % en chemins dont la moiti&eacute; en sous-bois &ndash; n&eacute;s en 2010 ou avant</p>\n</li>\n<li>\n<p class=\"mb-0\"><strong>Course enfants \"Les Arondes\"</strong>&nbsp;: 900 m &ndash; n&eacute;s en 2015 ou 2016</p>\n</li>\n<li>\n<p class=\"mb-0\"><strong>Course enfants \"Les &Eacute;cureuils\"</strong>&nbsp;: 600 m &ndash; n&eacute;s en 2017, 2018 ou 2019</p>\n</li>\n</ul>\n<p class=\"mb-0\">Plus d&rsquo;informations et toute l&rsquo;actualit&eacute; sur notre page Facebook</p>',
        '2026-04-26', 'https://www.facebook.com/profile.php?id=61585158960451', 'muches.jpg'),
       ('Semi du Val d\'Ancre (coquelicot)',
        '<p><strong>DIMANCHE 13 SEPTEMBRE 2026<br>AU STADE VELODROME D&rsquo;ALBERT&nbsp;</strong></p>\n<p>COURSE / TRAIL:</p>\n<ul>\n<li>Le Semi-Marathon du Val d&rsquo;Ancre TRAIL (Coquelicot)</li>\n<li>Airbus Trail 19km</li>\n<li>Albert Trail D&eacute;couverte 5 km</li>\n<li>Marche Loisir km / 13.5 km</li>\n</ul>\n<p>DEPARTS :&nbsp;</p>\n<ul>\n<li>&nbsp;9h pour le semi&nbsp;</li>\n<li>&nbsp;9h15 pour le trail courses80</li>\n</ul>\n<p>Informations : 06.46 175061</p>\n<p><br>R&eacute;compenses pour tous&nbsp;</p>',
        '2026-09-13', 'https://www.facebook.com/p/AMAAC-Albert-M%C3%A9aulte-A%C3%A9rospatiale-100077536203910/',
        'albert.jpg'),
       ('24 Heures Non-Stop d\'Eppeville',
        '<p>Samedi <span style=\"color: #e03e2d;\"><em><strong>9 mai</strong></em></span> et Dimanche <span style=\"color: #e03e2d;\"><em><strong>10 mai</strong></em></span>, de <span style=\"color: #e03e2d;\"><em><strong>10h &agrave; 10h</strong></em></span>...&nbsp; &nbsp; &nbsp; &nbsp; Epreuve labellis&eacute;e <span style=\"color: #e03e2d;\"><em><strong>bronze</strong></em></span>.</p>\n<p><span style=\"color: #e03e2d;\"><em><strong>24H en solo</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>24H en relais libres</strong></em></span> (de 4 &agrave; 24 relayeurs possibles), <span style=\"color: #e03e2d;\"><em><strong>12H en solo</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>12H en relais libres</strong></em></span> (de 3 &agrave; 12 relayeurs), <span style=\"color: #e03e2d;\"><em><strong>6H en solo</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>6H en relais libres</strong></em></span> (de 3 &agrave; 6 relayeurs), <span style=\"color: #e03e2d;\"><em><strong>3H en solo</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>3H en relais libres</strong></em></span> (3 relayeurs)...&nbsp; &nbsp; &nbsp; &nbsp;Attention, nombre de participants soumis &agrave; restriction pour ce qui concerne les coureurs <span style=\"color: #169179;\"><em><strong>solo</strong></em></span> (<span style=\"color: #e03e2d;\"><em><strong>99 maximum</strong></em></span>).&nbsp; &nbsp; &nbsp; Pas de restriction en ce qui concerne les relais.&nbsp; &nbsp; &nbsp; Changement de tarif des droits d\'inscription : le <span style=\"color: #e03e2d;\"><em><strong>20 avril</strong></em></span>.&nbsp; &nbsp; &nbsp; Fin des inscriptions le <strong><em><span style=\"color: #e03e2d;\">30 avril &agrave; minuit</span></em></strong>.</p>\n<p>Modalit&eacute;s d\'inscriptions, tarifs et inscriptions sur :&nbsp; &nbsp; &nbsp;<span style=\"color: #169179;\"><em><strong>klikego</strong></em></span> .</p>\n<p>+++++++++++++++</p>\n<p>En outre, <span style=\"color: #e03e2d;\"><em><strong>challenge d\'Eppeville</strong></em></span> par addition des performances r&eacute;alis&eacute;es sur <span style=\"color: #e03e2d;\"><em><strong>3km</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>5km</strong></em></span> et <span style=\"color: #e03e2d;\"><em><strong>10km</strong></em></span>.</p>\n<p>+++++++++++++++</p>\n<p>De plus <span style=\"color: #e03e2d;\"><em><strong>courses</strong></em></span> et <span style=\"color: #e03e2d;\"><em><strong>animations</strong></em></span> toutes les heures dont aucune cat&eacute;gorie d\'&acirc;ge n\'est exclue, <span style=\"color: #e03e2d;\"><em><strong>baby</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>&eacute;veil</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>poussin</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>benjamin</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>minime</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>3km</strong></em></span>, <span style=\"color: #e03e2d;\"><em><strong>5km</strong></em></span> et <span style=\"color: #e03e2d;\"><em><strong>10km</strong></em></span> sans oublier les pompiers, les secouristes, les personnalit&eacute;s, les d&eacute;guis&eacute;s, la <span style=\"color: #e03e2d;\"><em><strong>course aux flambeaux</strong></em></span> et une course ap&eacute;ritive.</p>\n<p>Modalit&eacute;s d\'inscription, tarifs, et inscriptions :&nbsp;<span style=\"color: #169179;\"><em><strong>24h.eppeville@laposte.net</strong></em></span>.</p>\n<p>Possibilit&eacute; de <span style=\"color: #3598db;\"><em><strong>s\'inscrire sur place</strong></em></span> pour <span style=\"color: #3598db;\"><em><strong>toutes les &eacute;preuves annexes</strong></em></span> jusqu\'&agrave; <em><strong><span style=\"color: #e03e2d;\">20mn</span></strong></em> de chaque d&eacute;part (challenge compris).</p>\n<p>Renseignements compl&eacute;mentaires : <span style=\"color: #236fa1;\"><strong><em>stephboguet@hotmail.com</em></strong></span> pour les courses de 24h 12h 6h et 3h individuels ou relais et <span style=\"color: #236fa1;\"><em><strong>24h.eppeville@laposte.net</strong></em></span> pour toutes les autres &eacute;preuves et animations.</p>\n<p>&nbsp;<span style=\"color: #843fa1;\"><strong>Bienvenue &agrave; Eppeville les 9 et 10 mai 2026 !</strong></span></p>',
        '2026-05-09', 'https://www.24heppeville.fr', '24h.jpg'),
       ('La belle d\'Authie',
        '<div>Apr&egrave;s une premi&egrave;re &eacute;dition r&eacute;ussie,&nbsp;La Belle d&rsquo;Authie revient pour sa 2ᵉ &eacute;dition&nbsp;avec de nouveaux formats et toujours autant de convivialit&eacute; !</div>\r\n<div>&nbsp;</div>\r\n<p>Deux formats adultes pour tous les go&ucirc;ts&nbsp;:</p>\r\n<ol>\r\n<li><span style=\"color: #2b3237;\">-&nbsp;</span>La Classique &ndash; 13 km&nbsp;: un format plus exigeant qui offre aux&nbsp;sportifs l&rsquo;occasion de s&rsquo;exprimer pleinement, sur un parcours m&ecirc;lant&nbsp;ville et nature, entre les rues de Fort-Mahon et espaces plus sauvages.</li>\r\n<li><span style=\"color: #2b3237;\">-&nbsp;</span>La Petite - 7 km&nbsp;(nouveaut&eacute; 2026) : un circuit accessible et dynamique, id&eacute;al pour les&nbsp;amateurs comme pour les coureurs confirm&eacute;s, au c&oelig;ur de la station.</li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p>Trois&nbsp;courses enfants, organis&eacute;es&nbsp;dans le centre de Fort-Mahon, permettront aux plus jeunes de vivre leur premi&egrave;re exp&eacute;rience de course &agrave; pied dans une ambiance festive, s&eacute;curis&eacute;e et familiale.</p>\r\n<p>&nbsp;</p>\r\n<p>Rendez-vous &agrave; Fort-Mahon-Plage pour une belle f&ecirc;te de la course &agrave; pied, &agrave; vivre en famille ou entre amis !</p>',
        '2026-04-25', 'https://www.facebook.com/p/La-Belle-dAuthie-61571641206044/', 'fortmayon.jpg'),
       ('Les doullennaises',
        '<ul class=\"fa-ul\">\n<li>\n<p class=\"mb-0\"><em>En 2026, les DOULENNAISES auront lieu le&nbsp;samedi 16 mai 2026.</em><strong><em>(Village dans la citadelle de Doullens)</em></strong></p>\n<p class=\"mb-0\">D&egrave;s aujourd&rsquo;hui, venez rejoindre cette grande f&ecirc;te populaire en vous inscrivant sur les parcours</p>\n<ul>\n<li><strong>Distances :</strong>&nbsp;Trail : 10 ou 21 km - Randonn&eacute;e : 10 km</li>\n<li><strong>Informations :</strong>&nbsp;MAILLY Hubert&nbsp; &ndash; T&eacute;l. 06.49 89 24 48.</li>\n<li><strong><em><u>Horaires et Inscriptions.</u></em></strong></li>\n</ul>\n<p class=\"mb-0\"><em><u>Inscription uniquement sur klikego.</u></em>&nbsp;Cl&ocirc;ture des inscriptions mercredi 13 mai - 22 h 00.</p>\n<p class=\"mb-0\">Les d&eacute;parts et arriv&eacute;es s\'effectueront &agrave; la Citadelle de Doullens.</p>\n<ul>\n<li><strong><em>Courses adultes:</em></strong></li>\n<li>Chronom&eacute;tr&eacute;es - d&eacute;parts.\n<ul>\n<li>18 h 00 - 10 km -&nbsp;<strong>inscription de 12.00 &euro;.</strong>&nbsp;(250 places maxi)&nbsp; D&eacute;nivel&eacute; de +150m - soit 11,5 km effort - Chemins et sous bois 80% (2010 et avant)</li>\n<li>17 h 30 - 21 km -<strong>&nbsp;inscription de 18.00 &euro;.</strong>&nbsp;(250 places maxi)&nbsp; D&eacute;nivel&eacute; de +350m - soit 24,5 km effort - Chemins et sous bois 90% (2006 et avant)</li>\n</ul>\n</li>\n<li><strong><em>Randonn&eacute;e:</em></strong>\n<ul>\n<li>10 km - depart libre entre 16 h 00 et 17 h 00<strong>&nbsp;-&nbsp;&nbsp;&nbsp; Inscription de 4,00&nbsp;&euro;</strong>&nbsp;ouverte &agrave; tous - (Pas de classement - 200 places maxi).</li>\n</ul>\n</li>\n</ul>\n<p class=\"mb-0\"><strong>Nous proposons la possibilit&eacute; de se restaurer sur place, (friterie) avec concert apr&egrave;s la remise des r&eacute;compenses..</strong></p>\n<ul>\n<li>Inscriptions documents &agrave; fournir:&nbsp;\n<ul>\n<li><strong>Pour les mineur(e)s:</strong>&nbsp;<a href=\"https://pps.athle.fr/users/sign_in\">Obtenir une attestation valable uniquement sur cette course.</a></li>\n<li>\n<p class=\"mb-0\"><strong>Pour&nbsp;les&nbsp;majeur(e)s:&nbsp;&nbsp;</strong>Sont&nbsp;accept&eacute;es uniquement les&nbsp;licences&nbsp;FFA&nbsp;(Comp&eacute;tition-Running-Entreprises)&nbsp;ou&nbsp;<a href=\"https://pps.athle.fr/\" target=\"_blank\" rel=\"noopener\">pour les non-licenci&eacute;s le PPS (Pass Parcours Pr&eacute;vention Sant&eacute;</a>.</p>\n</li>\n</ul>\n</li>\n<li>\n<p class=\"mb-0\">Retrait des dossards : &agrave; partir de 16 h00 jusqu\'&agrave; 30 mn avant le d&eacute;part de la course.</p>\n</li>\n</ul>\n</li>\n</ul>',
        '2026-05-16', 'https://www.facebook.com/lesfouleesd', 'doullens.jpg'),
       ('La longacoissienne 5 et 10 km',
        '<p class=\"mb-0\">5 KILOMETRES&nbsp; DEPART 14H45 &agrave; 200 m&eacute;tres de l\'arriv&eacute;e Rue Lucette Bonard</p>\n<p class=\"mb-0\">10 KILOMETRES DEPART 15H (2 tours ) d&eacute;part devant le parking de l\'Afral au niveau du parc des sports Rue Lucette Bonnard</p>\n<p class=\"mb-0\">MARCHE NORDIQUE&nbsp;(uniquement sur le 5 km)&nbsp; DEPART 14H45 m&ecirc;me d&eacute;part que le 5 km course et m&ecirc;me horaire</p>\n<p>&nbsp;</p>\n<p class=\"mb-0\"><u><strong>RETRAIT DES DOSSARDS :</strong></u></p>\n<p class=\"mb-0\">Le jour m&ecirc;me le 17&nbsp;mai au Gymnase Paul H&eacute;d&eacute; &agrave; Longueau d&egrave;s 13h00 et la veille chez notre partenaire Magasin Foul&eacute;es &agrave; Boves&nbsp;&nbsp;d&egrave;s 14h00 jusqu\'a 17h00.</p>\n<p class=\"mb-0\"><u><strong>RECOMPENSES :&nbsp;</strong></u></p>\n<p class=\"mb-0\">Au tirage au sort&nbsp;des dossards plusieurs lots &agrave; gagner. Ce lot vous sera remis lors du retrait de votre&nbsp;dossard.</p>\n<p class=\"mb-0\">M&eacute;dailles souvenir pour tous.</p>',
        '2026-05-17', 'https://www.facebook.com/courirauchu', 'longueau.jpg'),
       ('La Gliséenne',
        '<p>La course p&eacute;destre &laquo; La Glis&eacute;enne &raquo; se disputera le samedi 26 avril &agrave; Glisy selon&nbsp;<strong><em>une formule par &eacute;liminations successives</em></strong>&nbsp;sur la m&ecirc;me boucle de 2000 m et de la fa&ccedil;on suivante :</p>\r\n<p>15 h 00 D&eacute;part de la boucle 1 &agrave; courir dans le temps maxi de 12\'</p>\r\n<p>15 h 15 D&eacute;part des seuls coureurs ayant fini la boucle 1 en moins de 12\' et dans le temps maxi de 11\' pour la boucle 2</p>\r\n<p>15 h 30 D&eacute;part des seuls coureurs ayant fini la boucle 2 en moins de 11\' et dans le temps maxi de 10\'30 pour la boucle 3</p>\r\n<p>15 h 45 D&eacute;part pour les coureurs ayant fini la boucle 3 en moins de 10\'30 et dans le temps maxi de 10\'00 pour la boucle 4</p>\r\n<p>16 h 00 D&eacute;part pour les coureurs ayant fini la boucle 4 en moins de 10\'00 et dans le temps maxi de 9\'30 pour la boucle 5</p>\r\n<p>16 h 15 D&eacute;part pour les coureurs ayant fini la 5&deg; boucle en moins de 9\'30 et dans le temp maxi de 9\' pour la boucle 6</p>\r\n<p>&nbsp;16 h 30 D&eacute;part pour les coureurs ayant fini la boucle 6 en&nbsp;moins de 9\' et dans le temps maxi de 8\'30</p>\r\n<p>&nbsp;16 h 45 D&eacute;part pour les coureurs ayant fini la boucle 7 en&nbsp;&nbsp;moins de 8\'30 et dans le temps maxi de 8\'</p>\r\n<p>&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 17 h 00 D&eacute;part pour les coureurs ayant fini la boucle 8 en moins de 8\' et dans le temps maxi de 7\' 30</p>\r\n<p>17 h 10 D&eacute;part pour les coureurs ayant fini la boucle 9 en moins de 7\' 30 et dans le temps maxi de 7\'</p>\r\n<p>17 h 20 D&eacute;part pour les coureurs ayant fini la boucle 10 en moins de 7\' et dans le temps maxi de 6\'30</p>\r\n<p>&nbsp;17 h 30 D&eacute;part de la derni&egrave;re boucle</p>\r\n<p><strong>Prime aux 5 premiers hommes et 5 premi&egrave;res femmes : 100 &euro;, 80&nbsp;&euro;, 60&nbsp;&euro;, 40&euro; et 20 &euro;</strong></p>',
        '2026-04-25', 'https://courses80.fr/inscription/sinscrire.php?id=158', 'glisy.png'),
       ('L\'hortillonne',
        '<p>Epreuves ouvertes &agrave; tous, licenci&eacute;s ou non (certificat m&eacute;dical obligatoire), comp&eacute;titeurs ou joggers.</p>\r\n<ul>\r\n<li>10 km : Course entre sentiers et route</li>\r\n</ul>\r\n<p><strong>L</strong>\'<strong>HORTILLONNE</strong>&nbsp;fait partie de la&nbsp;<strong>F&ecirc;te des Hortillonnages</strong>&nbsp;: c\'est donc l\'occasion de d&eacute;couvrir un site naturel de premier ordre, de se restaurer aupr&egrave;s des diff&eacute;rents stands, d\'assister &agrave; des concerts, de profiter des jeux, man&egrave;ges, attractions mis &agrave; votre disposition....</p>\r\n<ul>\r\n<li>Nouveaut&eacute; 18 km :&nbsp;Course entre entiers et route</li>\r\n</ul>\r\n<ul>\r\n<li>Marche nordique : Parce que le sport doit se pratiquer &agrave; tous les niveaux, &agrave; tous les &acirc;ges et dans un large &eacute;ventail de disciplines, il a &eacute;t&eacute; ajout&eacute; une marche nordique de 10 km.</li>\r\n</ul>',
        '2026-05-30', 'https://uscathle.org/pages/public/', 'hortillone.jpg'),
       ('Courir la Jules Verne Enedis',
        '<p data-start=\"172\" data-end=\"222\">📍 Une journ&eacute;e 100 % sport pour tous les niveaux !</p>\n<p data-start=\"229\" data-end=\"489\">🕘 <strong data-start=\"232\" data-end=\"263\">09H00 &ndash; 10KM Mixte Confirm&eacute;</strong><br data-start=\"263\" data-end=\"266\">🔹 R&eacute;serv&eacute; aux participant(e)s avec un record inf&eacute;rieur &agrave; 45&rsquo;00 sur 10 km<br data-start=\"339\" data-end=\"342\">🔹 Ouvert &agrave; partir de la cat&eacute;gorie Cadet(te)s<br data-start=\"387\" data-end=\"390\">🏅 Label R&eacute;gional FFA<br data-start=\"411\" data-end=\"414\">📊 &Eacute;preuve classante et qualificative aux Championnats de France du 10 km</p>\n<hr data-start=\"491\" data-end=\"494\">\n<p data-start=\"496\" data-end=\"657\">🕙 <strong data-start=\"499\" data-end=\"531\">10H00 &ndash; 10KM Mixte Populaire</strong><br data-start=\"531\" data-end=\"534\">🔹 R&eacute;serv&eacute; aux participant(e)s avec un record sup&eacute;rieur &agrave; 45&rsquo;00 sur 10 km<br data-start=\"607\" data-end=\"610\">🔹 Ouvert &agrave; partir de la cat&eacute;gorie Cadet(te)s</p>\n<hr data-start=\"659\" data-end=\"662\">\n<p data-start=\"664\" data-end=\"865\">🕚 <strong data-start=\"667\" data-end=\"688\">11H15 &ndash; 5KM Mixte</strong><br data-start=\"688\" data-end=\"691\">🔹 Ouvert &agrave; tous les niveaux<br data-start=\"719\" data-end=\"722\">🔹 Ouvert &agrave; partir de la cat&eacute;gorie Minimes<br data-start=\"764\" data-end=\"767\">🏅 Label R&eacute;gional FFA<br data-start=\"788\" data-end=\"791\">📊 &Eacute;preuve classante et qualificative aux Championnats de France du 5 km</p>\n<hr data-start=\"867\" data-end=\"870\">\n<p data-start=\"872\" data-end=\"1060\">🕦 <strong data-start=\"875\" data-end=\"906\">11H30 &ndash; 5KM Marche Nordique</strong><br data-start=\"906\" data-end=\"909\">🥾 Marche avec b&acirc;tons<br data-start=\"930\" data-end=\"933\">🔹 Ouvert &agrave; tous<br data-start=\"949\" data-end=\"952\">🔹 Moins de 12 ans obligatoirement accompagn&eacute;(e)s d&rsquo;un adulte<br data-start=\"1013\" data-end=\"1016\">❌ Pas de classement &ndash; pas de chronom&eacute;trage</p>\n<hr data-start=\"1062\" data-end=\"1065\">\n<p data-start=\"1067\" data-end=\"1252\">🕦 <strong data-start=\"1070\" data-end=\"1098\">11H35 &ndash; 5KM Marche Rando</strong><br data-start=\"1098\" data-end=\"1101\">🚶 Marche sans b&acirc;tons<br data-start=\"1122\" data-end=\"1125\">🔹 Ouvert &agrave; tous<br data-start=\"1141\" data-end=\"1144\">🔹 Moins de 12 ans obligatoirement accompagn&eacute;(e)s d&rsquo;un adulte<br data-start=\"1205\" data-end=\"1208\">❌ Pas de classement &ndash; pas de chronom&eacute;trage</p>\n<hr data-start=\"1254\" data-end=\"1257\">\n<p data-start=\"1259\" data-end=\"1306\">🔥 <strong data-start=\"1262\" data-end=\"1306\">DEMANDE DE SAS &Eacute;LITE OU SAS PR&Eacute;F&Eacute;RENTIEL</strong></p>\n<p data-start=\"1308\" data-end=\"1483\">📌 Justificatif obligatoire d&rsquo;une performance r&eacute;alis&eacute;e en 2025 ou 2026<br data-start=\"1378\" data-end=\"1381\">📌 Demande &agrave; effectuer lors de l&rsquo;inscription en ligne<br data-start=\"1434\" data-end=\"1437\">📌 Validation obligatoire par l&rsquo;organisateur</p>\n<p data-start=\"1485\" data-end=\"1508\">🥇 SAS &Eacute;LITE &ndash; 10KM</p>\n<ul data-start=\"1509\" data-end=\"1562\">\n<li data-start=\"1509\" data-end=\"1535\">\n<p data-start=\"1511\" data-end=\"1535\">Homme : moins de 30&rsquo;30</p>\n</li>\n<li data-start=\"1536\" data-end=\"1562\">\n<p data-start=\"1538\" data-end=\"1562\">Femme : moins de 36&rsquo;00</p>\n</li>\n</ul>\n<p data-start=\"1564\" data-end=\"1594\">🥈 SAS PR&Eacute;F&Eacute;RENTIEL &ndash; 10KM</p>\n<ul data-start=\"1595\" data-end=\"1648\">\n<li data-start=\"1595\" data-end=\"1621\">\n<p data-start=\"1597\" data-end=\"1621\">Homme : moins de 33&rsquo;30</p>\n</li>\n<li data-start=\"1622\" data-end=\"1648\">\n<p data-start=\"1624\" data-end=\"1648\">Femme : moins de 40&rsquo;00</p>\n</li>\n</ul>\n<p data-start=\"1650\" data-end=\"1672\">🥇 SAS &Eacute;LITE &ndash; 5KM</p>\n<ul data-start=\"1673\" data-end=\"1726\">\n<li data-start=\"1673\" data-end=\"1699\">\n<p data-start=\"1675\" data-end=\"1699\">Homme : moins de 14&rsquo;30</p>\n</li>\n<li data-start=\"1700\" data-end=\"1726\">\n<p data-start=\"1702\" data-end=\"1726\">Femme : moins de 17&rsquo;20</p>\n</li>\n</ul>\n<p data-start=\"1728\" data-end=\"1757\">🥈 SAS PR&Eacute;F&Eacute;RENTIEL &ndash; 5KM</p>\n<ul data-start=\"1758\" data-end=\"1811\">\n<li data-start=\"1758\" data-end=\"1784\">\n<p data-start=\"1760\" data-end=\"1784\">Homme : moins de 15&rsquo;40</p>\n</li>\n<li data-start=\"1785\" data-end=\"1811\">\n<p data-start=\"1787\" data-end=\"1811\">Femme : moins de 18&rsquo;40</p>\n</li>\n</ul>\n<hr data-start=\"1813\" data-end=\"1816\">\n<p data-start=\"1818\" data-end=\"1930\" data-is-last-node=\"\" data-is-only-node=\"\">🎽 Que vous soyez comp&eacute;titeur, coureur loisir ou marcheur, rendez-vous en 2026 pour une &eacute;dition exceptionnelle !</p>',
        '2026-06-28', 'https://courirlajulesverne.com/', 'julesverne.png'),
       ('Le circuit du château fort',
        '<p>Course intra muros de 8800 m en 4 tours de 2200 m avec la mont&eacute;e a chaque tour de l\' escalier St martin pour un total de 588 Marches et la descente de l \'escalier St Jean pour un total 384 Marches &agrave; descendre.</p>\n<p><strong>D&eacute;part 18h30 Place de la gare, Retrait des dossards Hotel de Ville de Picquigny de 15 h &agrave; 18h00</strong></p>',
        '2026-07-13', 'http://circuitduchateaufort.free.fr/', 'picquigny.jpg'),
       ('Trail Centulois',
        '<p><strong>1&egrave;re &eacute;dition du Trail Centulois</strong></p>\n<p>📅&nbsp;<strong>Dimanche 24 mai 2026</strong><br>📍&nbsp;<strong>Oneux &ndash; Rue d&rsquo;Yrench</strong></p>\n<p>L&rsquo;AC Centuloise vous donne rendez-vous pour la&nbsp;<strong>1&egrave;re &eacute;dition du Trail Centulois</strong>&nbsp;!<br>Deux parcours&nbsp;<strong>100% nature</strong>&nbsp;vous attendent :</p>\n<p>➡️&nbsp;<strong>9 km</strong><br>➡️&nbsp;<strong>15 km</strong></p>\n<p>⏰&nbsp;<strong>D&eacute;part des deux courses : 9h45</strong></p>\n<div><hr></div>\n<p>📝&nbsp;<strong>INSCRIPTIONS EN LIGNE</strong><br>👉&nbsp;<a href=\"http://www.klikego.fr/\" data-cke-saved-href=\"http://www.klikego.fr\">www.klikego.fr</a></p>\n<p>⏳&nbsp;<span style=\"color: #ba372a;\"><strong>Cl&ocirc;ture des inscriptions : 23 mai 2026 &agrave; 12h00</strong></span></p>\n<p>💶&nbsp;<strong>Inscription possible sur place</strong><br>(+&nbsp;<strong>3 &euro; de majoration</strong>)</p>\n<div><hr></div>\n<p>🏆&nbsp;<strong>R&eacute;compenses</strong></p>\n<p><strong>9 km :</strong><br>🥇 Aux&nbsp;<strong>3 premiers et 3 premi&egrave;res au scratch</strong><br>🏅 Au&nbsp;<strong>1er de chaque cat&eacute;gorie (H/F)</strong></p>\n<p><strong>15 km :</strong><br>🥇 Aux&nbsp;<strong>5 premiers et 5 premi&egrave;res au scratch</strong><br>🏅 Au&nbsp;<strong>1er de chaque cat&eacute;gorie (H/F)</strong></p>\n<div><hr></div>\n<p>📄&nbsp;<strong>Informations administratives</strong></p>\n<p>👦&nbsp;<strong>Mineurs :</strong><br>Autorisation parentale (mod&egrave;le officiel)</p>\n<p>👟&nbsp;<strong>Athl&egrave;tes non licenci&eacute;s :</strong><br>PPS (<strong>Parcours Pr&eacute;vention Sant&eacute;</strong>) obligatoire<br><br></p>\n<div><hr></div>\n<p>📧&nbsp;<strong>Informations :</strong>&nbsp;<a href=\"mailto:accentuloise@yahoo.fr\" data-cke-saved-href=\"mailto:accentuloise@yahoo.fr\">accentuloise@yahoo.fr</a><br>📞&nbsp;<strong>T&eacute;l&eacute;phone :</strong>&nbsp;06 44 97 46 33</p>\n<p>On vous attend nombreux pour cette&nbsp;<strong>premi&egrave;re &eacute;dition nature et conviviale !</strong> 🌳🔥</p>',
        '2026-05-24', 'https://www.facebook.com/accentuloise/?locale=fr_FR', 'oneux.png'),
       ('la Collecti\'Run',
        '<div class=\"xdj266r x14z9mp xat24cr x1lziwak x1vvkbs\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tab/1/16/1f3c3_200d_2642.png\" alt=\"🏃&zwj;♂️\" width=\"16\" height=\"16\"></span>COLLECTI&rsquo;RUN : 5 KM POUR CHANGER DES VIES !&nbsp;<span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t3f/1/16/1f30d.png\" alt=\"🌍\" width=\"16\" height=\"16\"></span></div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\">Le 10 mai 2026, le Parc de la Hotoie s&rsquo;anime pour une cause exceptionnelle. Soyez au rendez-vous de la toute premi&egrave;re &eacute;dition de la Collecti&rsquo;Run, l&rsquo;&eacute;v&eacute;nement o&ugrave; chaque foul&eacute;e devient un geste de solidarit&eacute; !</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tf4/1/16/2728.png\" alt=\"✨\" width=\"16\" height=\"16\"></span>&nbsp;Un d&eacute;fi accessible &agrave; tous<br class=\"html-br\">Que vous soyez un runner aguerri &agrave; la recherche d&rsquo;un nouveau chrono ou un coureur souhaitant partager un moment en famille, ce parcours de 5 km est fait pour vous.</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\">Le concept : Rassembler sportifs, &eacute;tudiants et familles dans une ambiance survolt&eacute;e et bienveillante.<br class=\"html-br\">L&rsquo;&eacute;nergie : Un &eacute;v&eacute;nement convivial et dynamique pour repousser vos limites tout en restant connect&eacute; aux autres.</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t25/1/16/1f393.png\" alt=\"🎓\" width=\"16\" height=\"16\"></span>&nbsp;Un projet n&eacute; de la passion<br class=\"html-br\">Derri&egrave;re cette initiative se trouvent 5 &eacute;tudiants en 2&egrave;me ann&eacute;e d&rsquo;ergoth&eacute;rapie. Futurs professionnels du soin, ils ont mis toute leur &eacute;nergie pour cr&eacute;er une course qui allie le bien-&ecirc;tre physique &agrave; l&rsquo;engagement humain.</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t64/1/16/1f91d.png\" alt=\"🤝\" width=\"16\" height=\"16\"></span>&nbsp;Courir ici, agir l&agrave;-bas<br class=\"html-br\">En prenant votre dossard, vous faites bien plus que du sport. 100 % des b&eacute;n&eacute;fices seront revers&eacute;s &agrave; l&rsquo;association Handisables International.<br class=\"html-br\">Votre participation soutient directement les enfants et adolescents en situation de handicap au S&eacute;n&eacute;gal pour :</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tc3/1/16/1fa7a.png\" alt=\"🩺\" width=\"16\" height=\"16\"></span>&nbsp;Faciliter l&rsquo;acc&egrave;s aux soins m&eacute;dicaux et param&eacute;dicaux.<br class=\"html-br\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t49/1/16/1f4da.png\" alt=\"📚\" width=\"16\" height=\"16\"></span>&nbsp;Soutenir l&rsquo;&eacute;ducation et l&rsquo;apprentissage.<br class=\"html-br\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/td/1/16/1f4bc.png\" alt=\"💼\" width=\"16\" height=\"16\"></span>&nbsp;Ouvrir des perspectives professionnelles concr&egrave;tes.</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\"><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t6e/1/16/1f4ac.png\" alt=\"💬\" width=\"16\" height=\"16\"></span>&nbsp;&laquo; Le 10 mai, vous ne courrez pas seulement pour vous, vous courrez pour l&rsquo;avenir. &raquo;</div>\n<div class=\"x14z9mp xat24cr x1lziwak x1vvkbs xtlvy1s\">Pr&ecirc;t &agrave; relever le d&eacute;fi ? Bloquez la date dans votre agenda et rejoignez le mouvement Collecti&rsquo;Run !&nbsp;<span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/t39/1/16/1f3c1.png\" alt=\"🏁\" width=\"16\" height=\"16\"></span><span class=\"html-span xexx8yu xyri2b x18d9i69 x1c1uobl x1hl2dhg x16tdsg8 x1vvkbs x3nfvp2 x1j61x8r x1fcty0u xdj266r xat24cr xm2jcoa x1mpyi22 xxymvpz xlup9mm x1kky2od\"><img class=\"xz74otr x15mokao x1ga7v0g x16uus16 xbiv7yw\" src=\"https://static.xx.fbcdn.net/images/emoji.php/v9/tf4/1/16/2728.png\" alt=\"✨\" width=\"16\" height=\"16\"></span></div>',
        '2026-05-10', 'https://www.facebook.com/profile.php?id=61587662993911&locale=fr_FR', 'collecti run.png'),
       ('Corrida d\'Argoeuves',
        '<p>Seconde &eacute;dition de la corrida d\'Argoeuvres</p>\n<p>Distance : 5 km</p>\n<p>D&eacute;part : 15 heures</p>\n<p>Label : Bronze FFA</p>\n<p>Renseignement :</p>\n<p><strong>Cl&eacute;ment BOCQUILLON</strong></p>\n<div><strong>Amiens M&eacute;tropole Sports Events</strong></div>\n<div><strong>T&eacute;l : 07.77.90.05.88</strong></div>\n<div>\n<div><strong>Mail : <a href=\"mailto:amiensmetropolesportsevents@gmail.com\" target=\"_blank\" rel=\"noopener\">amiensmetropolesportsevents@gmail.com</a></strong></div>\n</div>\n<p>&nbsp;</p>',
        '2026-12-13', '', 'Argoeuves.png'),
       ('La corrid\'halloween de Montdidier',
        '<p>18h45 : course poussin 1500m</p>\r\n<p>19h00 : course benjamins 3000m</p>\r\n<p>19h30 : course 5 km en moins de 23 minutes</p>\r\n<p>20h15 : course&nbsp; 5 km en plus de 23 minutes</p>',
        '2026-10-31', 'https://www.facebook.com/lacorridhalloweendemontdidier/', 'montdidier.jpg'),
       ('Les Virades de l\'Espoir',
        '<p>Epreuves ouvertes &agrave; tous, licenci&eacute;s ou non (PPS obligatoire), comp&eacute;titeurs ou joggers.</p>\r\n<ul>\r\n<li>10 km : Une grande boucle de 10 km avec une c&ocirc;te au 3&egrave;me kilom&egrave;tre suivie d\'une descente rapide. Virage en &eacute;pingle &agrave; cheveux et pente raide mais courte, juste avant l\'arriv&eacute;e au stade. Course inscrite au challenge Courses 80</li>\r\n<li>D&eacute;fi &laquo;&nbsp;<em>Courir 5 km pour Vaincre la Mucoviscidose&nbsp;&raquo;.&nbsp;</em>Une seule c&ocirc;te au 4&egrave;me kilom&egrave;tre, pour remonter au stade. Course inscrite au challenge&nbsp; Courses 80.</li>\r\n</ul>\r\n<p>Vous avez la possibilit&eacute; de participer au deux &eacute;preuves pour le m&ecirc;me tarif</p>\r\n<p>&nbsp;</p>',
        '2026-09-27', 'https://uscathle.org/', '1.png'),
       ('LA ronde Picarde Running',
        '<p>EPREUVE OUVERTE &Agrave; TOUS<br>Sous l&rsquo;&eacute;gide de la FFA<br>D&egrave;s 14 ans pour le 5 km,<br>d&egrave;s 16 ans pour le 10 km<br>Avec licence agr&eacute;&eacute; par la FFA ou certificat<br>m&eacute;dical ou PPS / questionnaire de sant&eacute;.<br>Tarifs 10 km :<br>&bull; 20 &euro; : - de 18 ans / licenci&eacute;s FFA / groupes<br>&bull; 25 &euro; : autres<br>Tarifs 5 km :<br>&bull; 16 &euro; : - de 18 ans / licenci&eacute;s FFA / groupes<br>&bull; 19 &euro; : autres</p>\r\n<p>Dossard avec puce de chronom&eacute;trage<br>Dossard nominatif avec puce int&eacute;gr&eacute;e<br>Chronom&eacute;trage officiel<br>Classements par cat&eacute;gorie, sexe, et scratch.<br>M&eacute;daille finisher<br>M&eacute;daille offerte &agrave; tous les arrivants<br>Consignes<br>D&eacute;p&ocirc;t s&eacute;curis&eacute; des sacs personnels avant la course<br>Assistance m&eacute;dicale<br>Secouristes, m&eacute;decin<br>Photos officielles<br>Acc&egrave;s &agrave; des photos gratuites ou payantes apr&egrave;s la course<br>Goodies partenaires ou cadeau local<br>R&eacute;compenses podiums<br>Pour les 3 premiers scratch et par cat&eacute;gorie<br>U16 (14&ndash;15 ans) sur le format 5 km<br>U18 (moins de 18 ans) sur le format 10 km<br>U20 (moins de 20 ans) sur tous les formats<br>C1 - 20&gt;29 ans sur tous les formats<br>C2 - 30&gt;39 ans sur tous les formats<br>C3 - 40&gt;49 ans sur tous les formats<br>C4 - 50&gt;59 ans sur tous les formats<br>C5 - 60&gt;69 ans sur tous les formats<br>C6 - +70 ans sur tous les formats<br>H - Handisport<br>Parking d&eacute;di&eacute;<br>Acc&egrave;s r&eacute;serv&eacute; pour les participants</p>',
        '2026-09-19', 'https://running.cyclosportive-rondepicarde.fr/', 'rondepicarde.jpg'),
       ('Trail d\'Arquèves',
        '<p>Trois distance en trail</p>\r\n<ul>\r\n<li>5 km</li>\r\n<li>10 km</li>\r\n<li>21 km</li>\r\n</ul>\r\n<p>Une distance marche nordique de 21 km.&nbsp;</p>\r\n<p>D&eacute;part</p>\r\n<ul>\r\n<li>5 km - 10h45</li>\r\n<li>10 km - 10h30</li>\r\n<li>21 km - 10 h 00</li>\r\n<li>Marche Nordique - 9 h 00</li>\r\n</ul>',
        '2026-07-12', 'https://www.facebook.com/laMontinette/', 'montinette.jpg'),
       ('Trail des Crac\'s à Conty',
